module portfolio_optimizer(
    input [4:0] asset_values,
    output [4:0] optimal_selection
);
    assign optimal_selection[0] = asset_values[0];
    assign optimal_selection[1] = asset_values[1];
    assign optimal_selection[2] = asset_values[2];
    assign optimal_selection[3] = asset_values[3];
    assign optimal_selection[4] = (asset_values[3]) ? 1'b0 : asset_values[4];
endmodule
